class Solution {
public:
    string largestMerge(string word1, string word2) {
        string result;
        int i = 0, j = 0;
        while (i < word1.size() && j < word2.size()) {
            if (word1[i] > word2[j]) {
                result += word1[i++];
            } else {
                result += word2[j++];
            }
        }
        while (i < word1.size()) result += word1[i++];
        while (j < word2.size()) result += word2[j++];
        return result;
    }
};
